#include<bits/stdc++.h>
using namespace std;

const int N = 3e6 + 5;

inline int get(char x) {
    if(x >= 'a' && x <= 'z') return x - 'a';    
    if(x >= 'A' && x <= 'Z') return 26 + x - 'A';
    if(x >= '0' && x <= '9') return 52 + x - '0';
}

struct Trie {
    int num;
    int nxt[N][62];
    int cnt[N];
    void init() {
        num = 0;
        cnt[0] = 0;
        for(int i = 0; i < 62; i++) {
            nxt[0][i] = -1;
        }
    }
    int newnode() {
        cnt[++num] = 0;
        for(int i = 0; i < 62; i++) {
            nxt[num][i] = -1;
        }
        return num;
    }
    void insert(string s) {
        int p = 0, len = s.length();
        for(int i = 0; i < len; i++) {
            int c = get(s[i]);
            if(nxt[p][c] == -1) {
                nxt[p][c] = newnode();
            }
            p = nxt[p][c];
            cnt[p]++;
        }
    }
    int query(string s) {
        int p = 0, len = s.length();
        for(int i = 0; i < len; i++) {
            int c = get(s[i]);
            if(nxt[p][c] == -1) {
                return 0;
            }
            p = nxt[p][c];
        }
        return cnt[p];
    }
} a;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    int t;
    cin >> t;
    while(t--) {
        a.init();
        int n, q;
        cin >> n >> q;
        string s;
        for(int i = 1; i <= n; i++) {
            cin >> s;
            a.insert(s);
        }
        for(int i = 1; i <= q; i++) {
            cin >> s;
            cout << a.query(s) << '\n';
        }
    }
    return 0;
}
